import React from 'react';
import headerImage from './assets/header.png';

const Header = () => {
  return (
    <header
  style={{
    backgroundImage: `url(${headerImage})`,
    backgroundSize: 'cover', // Cover the entire header area
    backgroundPosition: 'center', // Center the image
    height: '300px', // Set a height for the header
  }}
>
      <h1 className="text-4xl font-bold">Welcome to EventHub</h1>
      <p className="mt-4 text-lg">Thailand's Premier Local Workshop Hub</p>
    </header>
  );
};

export default Header;
